package com.acme.service;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import org.springframework.stereotype.Service;

@Service
public class TemplateService {
    private static final String TEMPLATE_DIR = "/opt/app/templates";

    /**
     * Load a template by name. The name is expected to be a simple
     * filename like "welcome.html" or a subdirectory path like
     * "emails/reset-password.html".
     */
    public String loadTemplate(String templateName) throws IOException {
        // Developer attempts to sanitize by removing ".." sequences
        String sanitized = templateName.replace("..", "");

        Path templatePath = Paths.get(TEMPLATE_DIR, sanitized);

        // Check that the resolved path exists
        if (!Files.exists(templatePath)) {
            throw new IOException("Template not found: " + templateName);
        }

        return Files.readString(templatePath);
    }

    /**
     * Load a template with locale support.
     */
    public String loadLocalizedTemplate(String templateName, String locale) throws IOException {
        // Locale is user-controlled from Accept-Language header
        String localePath = locale + "/" + templateName;
        return loadTemplate(localePath);
    }
}
